import httpx
from PIL import Image
from io import BytesIO

r = httpx.get("http://100.104.189.48:9989/screenshot.png", timeout=10)
img = Image.open(BytesIO(r.content)).convert('RGB')
w, h = img.size

# Look at the right third (x=100-160) - TV area should be there
print("=== RIGHT SIDE (x=100-159, TV area) ===")
for y in range(0, h, 8):
    row = []
    for x in range(100, w):
        row.append(str(img.getpixel((x, y))[:3]))
    # compress consecutive same colors
    compressed = []
    for c in row:
        if not compressed or compressed[-1] != c:
            compressed.append(c)
    print(f"y={y:3d}: {' '.join(compressed)}")

# Scan for any pixel NOT in {(0,0,0), (255,255,255), (153,153,153), (85,85,85)}
wallpaper = {(0, 0, 0), (255, 255, 255), (153, 153, 153), (85, 85, 85), (0, 0, 0)}
interesting = set()
for y in range(h):
    for x in range(w):
        p = img.getpixel((x, y))
        if p not in wallpaper:
            interesting.add(p)

print(f"\nUnique non-wallpaper colors: {interesting}")"}

